import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, FileText, Maximize2, Minimize2, Edit3, X, Eye, EyeOff, Sparkles, Loader2, Wallet, Landmark, Info } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.55);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  // Voice State
  const [isListening, setIsListening] = useState(false);
  const sessionRef = useRef<any>(null);

  const previewContainerRef = useRef<HTMLDivElement>(null);
  const A4_WIDTH_PX = 794;

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      const data = JSON.parse(saved);
      setTransactions(data.transactions || []);
      setMonth(data.month || MONTHS[new Date().getMonth()]);
      setYear(data.year || new Date().getFullYear().toString());
      setPreviousBalance(data.previousBalance?.toString() || '0.00');
    }

    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    localStorage.setItem('idm_report_data', JSON.stringify({ transactions, month, year, previousBalance }));
  }, [transactions, month, year, previousBalance]);

  // --- DERIVED STATE: VALORES PARA SEDE ---
  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;

    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });

    return {
      dizimoSede,
      repasseSemid,
      parcelasSede,
      total: dizimoSede + repasseSemid + parcelasSede
    };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const containerHeight = previewContainerRef.current.clientHeight;
      const newZoom = (containerWidth - 60) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.2));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const addTransactions = (newItems: any[]) => {
    setTransactions(prev => {
      let updated = [...prev];
      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;
        const existingIndex = updated.findIndex(t => t.day === data.day && t.description.toLowerCase() === normalizedDesc.toLowerCase() && t.type === finalType);

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
        } else {
          updated.push({ id: uuidv4(), day: data.day, description: normalizedDesc, value: data.value, type: finalType });
        }

        if (data.type === TransactionType.ENTRY && (normalizedDesc.toLowerCase().includes("ceia"))) {
           updated.push({ id: uuidv4(), day: data.day, description: "REPASSE SEMID", value: data.value, type: TransactionType.EXIT });
        }
      });
      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const controlFunctions = [
      {
        name: 'add_entry',
        description: 'Adiciona uma nova transação.',
        parameters: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.STRING },
            description: { type: Type.STRING },
            value: { type: Type.NUMBER },
            type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] }
          },
          required: ['description', 'value', 'type']
        }
      },
      {
        name: 'update_report_config',
        description: 'Atualiza saldo, mês ou ano.',
        parameters: {
          type: Type.OBJECT,
          properties: {
            previousBalance: { type: Type.NUMBER },
            month: { type: Type.STRING },
            year: { type: Type.STRING }
          }
        }
      },
      { name: 'download_report', description: 'Gera PDF.' },
      { name: 'calculate_dizimo', description: 'Calcula dízimo 10%.' }
    ];

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: controlFunctions }],
          systemInstruction: 'Você auxilia na tesouraria IDM. Use as ferramentas para adicionar entradas ou atualizar o relatório.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor);
            processor.connect(audioContext.destination);
            setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                if (fc.name === 'update_report_config') {
                  if (fc.args.previousBalance !== undefined) setPreviousBalance(fc.args.previousBalance.toString());
                  if (fc.args.month) {
                    const matchedMonth = MONTHS.find(m => m.toLowerCase().includes(fc.args.month.toLowerCase()));
                    if (matchedMonth) setMonth(matchedMonth);
                  }
                  if (fc.args.year) setYear(fc.args.year.toString());
                }
                if (fc.name === 'download_report') handleDownloadPDF();
                if (fc.name === 'calculate_dizimo') calculateDizimoSede();
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false),
          onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) {
      setIsListening(false);
    }
  };

  const toggleVoice = () => {
    if (isListening) {
      sessionRef.current?.stop();
      setIsListening(false);
    } else {
      startVoiceSession();
    }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {/* SIDEBAR */}
      {!isFullPreview && (
        <div className="w-full lg:w-[420px] bg-slate-900 border-r border-slate-800 flex flex-col h-[55%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden">
                 <Eye size={16} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar pb-10">

            {/* Configuração */}
            <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-3 rounded-xl border border-slate-800">
              <div>
                <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                  {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                </select>
              </div>
              <div>
                <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
              </div>
              <div className="col-span-2">
                <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
              </div>
            </div>

            <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={toggleVoice} />

            <button onClick={calculateDizimoSede} className="w-full py-2.5 bg-purple-600/10 hover:bg-purple-600/20 text-purple-400 border border-purple-600/20 rounded-lg text-[10px] font-bold flex items-center justify-center gap-2 uppercase">
              <Sparkles size={14}/> Lançar Dízimo Sede (10%)
            </button>

            {/* Lançamentos */}
            <div className="space-y-2">
              <h3 className="text-[9px] uppercase font-bold text-slate-500 tracking-widest px-1">Lançamentos</h3>
              <div className="space-y-1.5">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className="group bg-slate-800/40 border border-slate-800 hover:border-slate-700 p-2.5 rounded-xl flex items-center justify-between transition-all">
                    <div className="flex flex-col min-w-0">
                      <span className="text-[9px] font-bold text-slate-500 uppercase">DIA {t.day}</span>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate pr-2">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-xs font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>
                        {t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                      <div className="flex gap-1">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={12} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={12} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* CAIXA REMESSA SEDE (MAIS DISCRETA NO FINAL) */}
            <div className="mt-6 pt-4 border-t border-slate-800">
               <div className="flex items-center gap-2 mb-2 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase">Valores p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-3 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px]">
                    <span className="text-slate-500 uppercase">Dízimo Sede + SEMID:</span>
                    <span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                  <div className="flex justify-between text-[11px]">
                    <span className="text-slate-500 uppercase">Parcelas/Compras:</span>
                    <span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center">
                    <span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span>
                    <span className="text-sm font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-3 rounded-xl flex items-center justify-center gap-2 disabled:opacity-50 transition-all uppercase text-sm">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO
            </button>
          </div>
        </div>
      )}

      {/* PREVIEW AREA */}
      <div className={`flex-1 flex flex-col bg-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full' : 'h-[45%] lg:h-full'}`}>

        {/* Overlays */}
        <div className="absolute top-4 right-4 z-40 flex gap-2 no-print">
           {isFullPreview && (
             <button onClick={() => setIsFullPreview(false)} className="bg-red-600 hover:bg-red-700 text-white p-3 rounded-full shadow-xl transition-all">
               <X size={20} />
             </button>
           )}
        </div>

        {/* Zoom Control */}
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-4 shrink-0 no-print">
           <span className="text-[9px] font-black text-slate-500 tracking-widest uppercase">Visualizador A4</span>
           <div className="flex items-center gap-3 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.1, z-0.05))} className="p-1 text-slate-400 hover:text-white"><ZoomOut size={16}/></button>
             <span className="text-[10px] font-mono font-bold w-10 text-center text-slate-300">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-400 hover:text-white"><ZoomIn size={16}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-400 hover:text-blue-400 ml-1"><Maximize2 size={14}/></button>
           </div>
        </div>

        {/* The Paper Container */}
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-2 lg:p-8 flex justify-center bg-slate-900/50 custom-scrollbar relative">
           <div 
             className="origin-top transition-transform duration-200 shadow-2xl rounded-sm mb-10" 
             style={{ 
               transform: `scale(${zoom})`,
               minWidth: `${A4_WIDTH_PX}px`
             }}
           >
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} />
              </div>
           </div>
        </div>
      </div>

      {/* EDIT MODAL */}
      {editingTransaction && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden">
            <div className="p-4 bg-slate-800 border-b border-slate-700 flex justify-between items-center">
              <h3 className="font-bold text-sm uppercase tracking-tight flex items-center gap-2">
                <Edit3 size={16}/> Editar Lançamento
              </h3>
              <button onClick={() => setEditingTransaction(null)} className="p-1 hover:bg-slate-700 rounded-full"><X size={20}/></button>
            </div>
            <div className="p-6 space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none uppercase" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none font-mono" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option>
                    <option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="pt-4 flex gap-3">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-lg font-bold uppercase text-[10px]">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold uppercase text-[10px]">Salvar</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  // Voice State
  const [isListening, setIsListening] = useState(false);
  const sessionRef = useRef<any>(null);

  const previewContainerRef = useRef<HTMLDivElement>(null);
  const A4_WIDTH_PX = 794;

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      const data = JSON.parse(saved);
      setTransactions(data.transactions || []);
      setMonth(data.month || MONTHS[new Date().getMonth()]);
      setYear(data.year || new Date().getFullYear().toString());
      setPreviousBalance(data.previousBalance?.toString() || '0.00');
    }

    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    localStorage.setItem('idm_report_data', JSON.stringify({ transactions, month, year, previousBalance }));
  }, [transactions, month, year, previousBalance]);

  // --- DERIVED STATE: VALORES PARA SEDE ---
  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;

    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });

    return {
      dizimoSede,
      repasseSemid,
      parcelasSede,
      total: dizimoSede + repasseSemid + parcelasSede
    };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const addTransactions = (newItems: any[]) => {
    setTransactions(prev => {
      let updated = [...prev];
      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');

        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());

        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        // Check for duplicates
        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
        } else {
          updated.push({ id: uuidv4(), day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
        }

        // AUTO-CORRECTION: If "Ceia" entry, add "REPASSE SEMID" for the SAME day
        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             updated.push({ id: uuidv4(), day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             // If already exists for that day, just add the value
             existingRepasse.value += data.value;
           }
        }
      });
      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const controlFunctions = [
      {
        name: 'add_entry',
        description: 'Adiciona uma nova transação.',
        parameters: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.STRING },
            description: { type: Type.STRING },
            value: { type: Type.NUMBER },
            type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] }
          },
          required: ['description', 'value', 'type']
        }
      },
      {
        name: 'update_report_config',
        description: 'Atualiza saldo, mês ou ano.',
        parameters: {
          type: Type.OBJECT,
          properties: {
            previousBalance: { type: Type.NUMBER },
            month: { type: Type.STRING },
            year: { type: Type.STRING }
          }
        }
      },
      { name: 'download_report', description: 'Gera PDF.' },
      { name: 'calculate_dizimo', description: 'Calcula dízimo 10%.' }
    ];

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: controlFunctions }],
          systemInstruction: 'Você auxilia na tesouraria IDM. Use as ferramentas para adicionar entradas ou atualizar o relatório. Ao adicionar "Ceia", o sistema cuida do repasse.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor);
            processor.connect(audioContext.destination);
            setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                if (fc.name === 'update_report_config') {
                  if (fc.args.previousBalance !== undefined) setPreviousBalance(fc.args.previousBalance.toString());
                  if (fc.args.month) {
                    const matchedMonth = MONTHS.find(m => m.toLowerCase().includes(fc.args.month.toLowerCase()));
                    if (matchedMonth) setMonth(matchedMonth);
                  }
                  if (fc.args.year) setYear(fc.args.year.toString());
                }
                if (fc.name === 'download_report') handleDownloadPDF();
                if (fc.name === 'calculate_dizimo') calculateDizimoSede();
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false),
          onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) {
      setIsListening(false);
    }
  };

  const toggleVoice = () => {
    if (isListening) {
      sessionRef.current?.stop();
      setIsListening(false);
    } else {
      startVoiceSession();
    }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {/* SIDEBAR - 75% WIDTH */}
      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden">
                 <Eye size={16} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {/* Configuração */}
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
              </div>

              <div className="md:col-span-2">
                <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={toggleVoice} />
                <button onClick={calculateDizimoSede} className="mt-3 w-full py-2 bg-purple-600/10 hover:bg-purple-600/20 text-purple-400 border border-purple-600/20 rounded-lg text-[10px] font-bold flex items-center justify-center gap-2 uppercase transition-colors">
                  <Sparkles size={14}/> Lançar Dízimo Sede (10%)
                </button>
              </div>
            </div>

            {/* Lançamentos */}
            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Recentes
                <span className="text-[9px] normal-case font-normal text-slate-600">Total: {transactions.length} itens</span>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className="group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all shadow-sm">
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>
                          {t.type}
                        </span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>
                        {t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400" title="Editar"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500" title="Excluir"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
                {transactions.length === 0 && (
                  <div className="col-span-full py-12 text-center border-2 border-dashed border-slate-800 rounded-2xl">
                    <p className="text-slate-600 text-xs uppercase font-bold tracking-widest">Nenhum lançamento registrado</p>
                  </div>
                )}
              </div>
            </div>

            {/* CAIXA REMESSA SEDE (DISCRETA) */}
            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2.5 border border-slate-800/50 shadow-inner">
                  <div className="flex justify-between text-[11px]">
                    <span className="text-slate-500 uppercase">Dízimo Sede + SEMID:</span>
                    <span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                  <div className="flex justify-between text-[11px]">
                    <span className="text-slate-500 uppercase">Parcelas/Compras:</span>
                    <span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                  <div className="pt-2.5 border-t border-slate-700 flex justify-between items-center">
                    <span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span>
                    <span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-xl flex items-center justify-center gap-3 disabled:opacity-50 transition-all uppercase text-sm shadow-xl shadow-yellow-500/10">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} GERAR RELATÓRIO FINAL (PDF)
            </button>
          </div>
        </div>
      )}

      {/* PREVIEW AREA - 25% WIDTH */}
      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>

        {/* Overlays */}
        <div className="absolute top-4 right-4 z-40 flex gap-2 no-print">
           {isFullPreview && (
             <button onClick={() => setIsFullPreview(false)} className="bg-red-600 hover:bg-red-700 text-white p-3 rounded-full shadow-2xl transition-all">
               <X size={20} />
             </button>
           )}
        </div>

        {/* Zoom Control */}
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0 no-print">
           <span className="text-[8px] font-black text-slate-500 tracking-widest uppercase">Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-1.5 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold w-8 text-center text-slate-400">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} title="Ajustar" className="p-1 text-slate-500 hover:text-blue-400 border-l border-slate-800 ml-1"><Maximize2 size={12}/></button>
           </div>
        </div>

        {/* The Paper Container */}
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 custom-scrollbar relative items-start">
           <div 
             className="origin-top transition-transform duration-200 shadow-2xl rounded-sm mb-12" 
             style={{ 
               transform: `scale(${zoom})`,
               minWidth: `${A4_WIDTH_PX}px`
             }}
           >
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} />
              </div>
           </div>
        </div>
      </div>

      {/* EDIT MODAL */}
      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden">
            <div className="p-4 bg-slate-800 border-b border-slate-700 flex justify-between items-center">
              <h3 className="font-bold text-sm uppercase tracking-tight flex items-center gap-2">
                <Edit3 size={16}/> Editar Lançamento
              </h3>
              <button onClick={() => setEditingTransaction(null)} className="p-1 hover:bg-slate-700 rounded-full"><X size={20}/></button>
            </div>
            <div className="p-6 space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none uppercase" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none font-mono" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option>
                    <option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="pt-4 flex gap-3">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-lg font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold uppercase text-[10px] transition-colors">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, FileUp, FileDown } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const fileInputImportRef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }

    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    localStorage.setItem('idm_report_data', JSON.stringify({ transactions, month, year, previousBalance }));
  }, [transactions, month, year, previousBalance]);

  // --- DERIVED STATE: VALORES PARA SEDE ---
  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;

    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });

    return {
      dizimoSede,
      repasseSemid,
      parcelasSede,
      total: dizimoSede + repasseSemid + parcelasSede
    };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const addTransactions = (newItems: any[]) => {
    setTransactions(prev => {
      let updated = [...prev];
      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');
        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
        } else {
          updated.push({ id: uuidv4(), day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
        }

        // AUTO-CORRECTION: "Ceia" entry -> "REPASSE SEMID" same day
        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             updated.push({ id: uuidv4(), day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });
      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  // --- EXPORTAR E IMPORTAR DADOS (JSON) ---
  const handleExportBackup = () => {
    const data = { transactions, month, year, previousBalance };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Backup_Relatorio_${month}_${year}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!confirm("Isso irá substituir os dados atuais pelos dados do arquivo. Deseja continuar?")) {
      if (fileInputImportRef.current) fileInputImportRef.current.value = '';
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.transactions) setTransactions(json.transactions);
        if (json.month) setMonth(json.month);
        if (json.year) setYear(json.year);
        if (json.previousBalance !== undefined) setPreviousBalance(json.previousBalance.toString());
        alert("Dados importados com sucesso!");
      } catch (err) {
        alert("Erro ao ler o arquivo de backup. Verifique se o formato está correto.");
      }
    };
    reader.readAsText(file);
    if (fileInputImportRef.current) fileInputImportRef.current.value = '';
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const controlFunctions = [
      {
        name: 'add_entry',
        description: 'Adiciona uma nova transação.',
        parameters: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.STRING },
            description: { type: Type.STRING },
            value: { type: Type.NUMBER },
            type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] }
          },
          required: ['description', 'value', 'type']
        }
      }
    ];

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: controlFunctions }],
          systemInstruction: 'Você auxilia na tesouraria IDM. Ao receber lançamentos, extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor);
            processor.connect(audioContext.destination);
            setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false),
          onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) {
      setIsListening(false);
    }
  };

  const toggleVoice = () => {
    if (isListening) {
      sessionRef.current?.stop();
      setIsListening(false);
    } else {
      startVoiceSession();
    }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {/* SIDEBAR - 75% WIDTH */}
      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <div className="flex items-center gap-4">
               <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
                <Calculator size={18} /> Financeiro IDM
               </h1>

               {/* BOTÕES DE BACKUP */}
               <div className="hidden md:flex items-center gap-2 border-l border-slate-800 pl-4">
                  <button onClick={handleExportBackup} className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg text-[10px] font-bold uppercase transition-colors" title="Salvar Backup para editar depois">
                    <FileDown size={14} /> Exportar Backup
                  </button>
                  <button onClick={() => fileInputImportRef.current?.click()} className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg text-[10px] font-bold uppercase transition-colors" title="Carregar Backup salvo">
                    <FileUp size={14} /> Importar Backup
                  </button>
                  <input type="file" ref={fileInputImportRef} accept=".json" onChange={handleImportBackup} className="hidden" />
               </div>
            </div>

            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden">
                 <Eye size={16} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {/* Configuração */}
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
              </div>

              <div className="md:col-span-2">
                <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={toggleVoice} />
                <button onClick={calculateDizimoSede} className="mt-3 w-full py-2 bg-purple-600/10 hover:bg-purple-600/20 text-purple-400 border border-purple-600/20 rounded-lg text-[10px] font-bold flex items-center justify-center gap-2 uppercase transition-colors">
                  <Sparkles size={14}/> Lançar Dízimo Sede (10%)
                </button>
              </div>
            </div>

            {/* Lançamentos */}
            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <span className="text-[9px] normal-case font-normal text-slate-600">Total: {transactions.length} itens</span>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className="group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all shadow-sm">
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>
                          {t.type}
                        </span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>
                        {t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400" title="Editar"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500" title="Excluir"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
                {transactions.length === 0 && (
                  <div className="col-span-full py-12 text-center border-2 border-dashed border-slate-800 rounded-2xl">
                    <p className="text-slate-600 text-xs uppercase font-bold tracking-widest">Nenhum lançamento registrado</p>
                  </div>
                )}
              </div>
            </div>

            {/* CAIXA REMESSA SEDE (DISCRETA) */}
            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2.5 border border-slate-800/50 shadow-inner">
                  <div className="flex justify-between text-[11px]">
                    <span className="text-slate-500 uppercase">Dízimo Sede + SEMID:</span>
                    <span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                  <div className="flex justify-between text-[11px]">
                    <span className="text-slate-500 uppercase">Parcelas/Compras:</span>
                    <span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                  <div className="pt-2.5 border-t border-slate-700 flex justify-between items-center">
                    <span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span>
                    <span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-xl flex items-center justify-center gap-3 disabled:opacity-50 transition-all uppercase text-sm shadow-xl shadow-yellow-500/10">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} GERAR RELATÓRIO FINAL (PDF)
            </button>
          </div>
        </div>
      )}

      {/* PREVIEW AREA - 25% WIDTH */}
      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>

        {/* Overlays */}
        <div className="absolute top-4 right-4 z-40 flex gap-2 no-print">
           {isFullPreview && (
             <button onClick={() => setIsFullPreview(false)} className="bg-red-600 hover:bg-red-700 text-white p-3 rounded-full shadow-2xl transition-all">
               <X size={20} />
             </button>
           )}
        </div>

        {/* Zoom Control */}
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0 no-print">
           <span className="text-[8px] font-black text-slate-500 tracking-widest uppercase">Visualização Folha</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-1.5 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold w-8 text-center text-slate-400">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} title="Ajustar" className="p-1 text-slate-500 hover:text-blue-400 border-l border-slate-800 ml-1"><Maximize2 size={12}/></button>
           </div>
        </div>

        {/* The Paper Container */}
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 custom-scrollbar relative items-start">
           <div 
             className="origin-top transition-transform duration-200 shadow-2xl rounded-sm mb-12" 
             style={{ 
               transform: `scale(${zoom})`,
               minWidth: `${A4_WIDTH_PX}px`
             }}
           >
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} />
              </div>
           </div>
        </div>
      </div>

      {/* EDIT MODAL */}
      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden">
            <div className="p-4 bg-slate-800 border-b border-slate-700 flex justify-between items-center">
              <h3 className="font-bold text-sm uppercase tracking-tight flex items-center gap-2">
                <Edit3 size={16}/> Editar Lançamento
              </h3>
              <button onClick={() => setEditingTransaction(null)} className="p-1 hover:bg-slate-700 rounded-full"><X size={20}/></button>
            </div>
            <div className="p-6 space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none uppercase" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none font-mono" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option>
                    <option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="pt-4 flex gap-3">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-lg font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold uppercase text-[10px] transition-colors">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, FileUp, FileDown, History, Camera } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const fileInputImportRef = useRef<HTMLInputElement>(null);
  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    localStorage.setItem('idm_report_data', JSON.stringify({ transactions, month, year, previousBalance }));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const addTransactions = (newItems: any[]) => {
    setTransactions(prev => {
      let updated = [...prev];
      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');
        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
        } else {
          updated.push({ id: uuidv4(), day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             updated.push({ id: uuidv4(), day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });
      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleExportBackup = () => {
    const data = { transactions, month, year, previousBalance };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Dados_Relatorio_${month}_${year}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!confirm("Isso irá substituir os dados atuais. Deseja continuar?")) {
      if (fileInputImportRef.current) fileInputImportRef.current.value = '';
      return;
    }
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.transactions) setTransactions(json.transactions);
        if (json.month) setMonth(json.month);
        if (json.year) setYear(json.year);
        if (json.previousBalance !== undefined) setPreviousBalance(json.previousBalance.toString());
      } catch (err) { alert("Erro ao ler o arquivo."); }
    };
    reader.readAsText(file);
    if (fileInputImportRef.current) fileInputImportRef.current.value = '';
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const results = await parseTransactionImage(base64Content, file.type);
        if (results && results.length > 0) {
          addTransactions(results);
          alert(`${results.length} itens extraídos do seu relatório antigo!`);
        } else {
          alert("Não conseguimos ler dados deste arquivo. Tente uma foto mais nítida.");
        }
      } catch (err) {
        alert("Erro ao processar com IA.");
      } finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) { setIsListening(false); }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden">
                 <Eye size={16} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={() => isListening ? sessionRef.current?.stop() : startVoiceSession()} />

                {/* ÁREA DE GESTÃO DE DADOS - IMPORTANTE */}
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
                   <button onClick={handleExportBackup} className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-lg text-[10px] font-bold uppercase border border-slate-700 transition-colors">
                     <FileDown size={14} /> Salvar Trabalho
                   </button>
                   <button onClick={() => fileInputImportRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-lg text-[10px] font-bold uppercase border border-slate-700 transition-colors">
                     <FileUp size={14} /> Abrir Trabalho
                   </button>
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-blue-600/10 hover:bg-blue-600/20 text-blue-400 rounded-lg text-[10px] font-bold uppercase border border-blue-600/20 transition-colors">
                     {isProcessingIA ? <Loader2 size={14} className="animate-spin" /> : <Camera size={14} />} 
                     Ler Relatório Antigo
                   </button>
                   <input type="file" ref={fileInputImportRef} accept=".json" onChange={handleImportBackup} className="hidden" />
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className="group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all">
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase">Resumo p/ Sede</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar</h3>
              <button onClick={() => setEditingTransaction(null)}><X size={20}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="col-span-1 bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs" />
                <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="col-span-3 bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono" />
                <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs">
                  <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                </select>
              </div>
              <button onClick={() => updateTransaction(editingTransaction)} className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold uppercase text-[10px]">Salvar Alterações</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, FileUp, FileDown, History, Camera, RotateCcw } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const fileInputImportRef = useRef<HTMLInputElement>(null);
  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    localStorage.setItem('idm_report_data', JSON.stringify({ transactions, month, year, previousBalance }));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais e o saldo serão apagados permanentemente.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      setMonth(MONTHS[new Date().getMonth()]);
      setYear(new Date().getFullYear().toString());
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    setTransactions(prev => {
      let updated = [...prev];
      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');
        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
        } else {
          updated.push({ id: uuidv4(), day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             updated.push({ id: uuidv4(), day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });
      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleExportBackup = () => {
    const data = { transactions, month, year, previousBalance };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Dados_Relatorio_${month}_${year}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!confirm("Isso irá substituir os dados atuais. Deseja continuar?")) {
      if (fileInputImportRef.current) fileInputImportRef.current.value = '';
      return;
    }
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.transactions) setTransactions(json.transactions);
        if (json.month) setMonth(json.month);
        if (json.year) setYear(json.year);
        if (json.previousBalance !== undefined) setPreviousBalance(json.previousBalance.toString());
      } catch (err) { alert("Erro ao ler o arquivo."); }
    };
    reader.readAsText(file);
    if (fileInputImportRef.current) fileInputImportRef.current.value = '';
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const results = await parseTransactionImage(base64Content, file.type);
        if (results && results.length > 0) {
          addTransactions(results);
          alert(`${results.length} itens extraídos do seu relatório antigo!`);
        } else {
          alert("Não conseguimos ler dados deste arquivo. Tente uma foto mais nítida.");
        }
      } catch (err) {
        alert("Erro ao processar com IA.");
      } finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) { setIsListening(false); }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden">
                 <Eye size={16} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                {/* BOTÃO NOVO RELATÓRIO */}
                <div className="col-span-2 pt-1">
                  <button 
                    onClick={handleNewReport}
                    className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors"
                  >
                    <RotateCcw size={14} /> Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={() => isListening ? sessionRef.current?.stop() : startVoiceSession()} />

                {/* ÁREA DE GESTÃO DE DADOS */}
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
                   <button onClick={handleExportBackup} className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-lg text-[10px] font-bold uppercase border border-slate-700 transition-colors">
                     <FileDown size={14} /> Salvar Trabalho
                   </button>
                   <button onClick={() => fileInputImportRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-lg text-[10px] font-bold uppercase border border-slate-700 transition-colors">
                     <FileUp size={14} /> Abrir Trabalho
                   </button>
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-blue-600/10 hover:bg-blue-600/20 text-blue-400 rounded-lg text-[10px] font-bold uppercase border border-blue-600/20 transition-colors">
                     {isProcessingIA ? <Loader2 size={14} className="animate-spin" /> : <Camera size={14} />} 
                     Ler Relatório Antigo
                   </button>
                   <input type="file" ref={fileInputImportRef} accept=".json" onChange={handleImportBackup} className="hidden" />
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className="group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all">
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase">Resumo p/ Sede</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar</h3>
              <button onClick={() => setEditingTransaction(null)}><X size={20}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="col-span-1 bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs" />
                <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="col-span-3 bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono" />
                <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs">
                  <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                </select>
              </div>
              <button onClick={() => updateTransaction(editingTransaction)} className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold uppercase text-[10px]">Salvar Alterações</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

