import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, FileUp, FileDown, History, Camera, RotateCcw } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage, parseTransactionInput } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  const fileInputImportRef = useRef<HTMLInputElement>(null);
  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Carregar dados salvos automaticamente ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Salvar automaticamente em cada mudança (Auto-Save Permanente)
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais e o saldo serão apagados permanentemente.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      setMonth(MONTHS[new Date().getMonth()]);
      setYear(new Date().getFullYear().toString());
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');
        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
          lastId = updated[existingIndex].id;
        } else {
          const id = uuidv4();
          updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
          lastId = id;
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             const repasseId = uuidv4();
             updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!confirm("Isso irá substituir os dados atuais pelos dados do arquivo. Deseja continuar?")) {
      if (fileInputImportRef.current) fileInputImportRef.current.value = '';
      return;
    }
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.transactions) setTransactions(json.transactions);
        if (json.month) setMonth(json.month);
        if (json.year) setYear(json.year);
        if (json.previousBalance !== undefined) setPreviousBalance(json.previousBalance.toString());
      } catch (err) { alert("Erro ao ler o arquivo."); }
    };
    reader.readAsText(file);
    if (fileInputImportRef.current) fileInputImportRef.current.value = '';
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {}
      finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) { setIsListening(false); }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
                 {lastAddedId && <span className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full animate-ping"></span>}
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={() => isListening ? sessionRef.current?.stop() : startVoiceSession()} />

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                   <button onClick={() => fileInputImportRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 px-3 py-3 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-xl text-[10px] font-black uppercase border border-slate-700 transition-all active:scale-95">
                     <FileUp size={16} /> Abrir Trabalho Salvo
                   </button>
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="flex-1 flex items-center justify-center gap-2 px-3 py-3 bg-blue-600/10 hover:bg-blue-600/20 text-blue-400 rounded-xl text-[10px] font-black uppercase border border-blue-600/20 transition-all active:scale-95">
                     {isProcessingIA ? <Loader2 size={16} className="animate-spin" /> : <Camera size={16} />} 
                     Ler Relatório Antigo (IA)
                   </button>
                   <input type="file" ref={fileInputImportRef} accept=".json" onChange={handleImportBackup} className="hidden" />
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O progresso é salvo automaticamente a cada alteração</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage, parseTransactionInput } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Carregar dados salvos automaticamente ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Salvar automaticamente em cada mudança (Auto-Save Permanente)
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais e o saldo serão apagados permanentemente.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      setMonth(MONTHS[new Date().getMonth()]);
      setYear(new Date().getFullYear().toString());
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');
        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
          lastId = updated[existingIndex].id;
        } else {
          const id = uuidv4();
          updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
          lastId = id;
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             const repasseId = uuidv4();
             updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {}
      finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) { setIsListening(false); }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
                 {lastAddedId && <span className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full animate-ping"></span>}
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={() => isListening ? sessionRef.current?.stop() : startVoiceSession()} />

                <div className="flex flex-col gap-2">
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95">
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente no navegador</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage, parseTransactionInput } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Carregar dados salvos automaticamente ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Salvar automaticamente em cada mudança (Auto-Save Permanente)
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais e o saldo serão apagados permanentemente.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      setMonth(MONTHS[new Date().getMonth()]);
      setYear(new Date().getFullYear().toString());
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');
        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
          lastId = updated[existingIndex].id;
        } else {
          const id = uuidv4();
          updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
          lastId = id;
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             const repasseId = uuidv4();
             updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));

    // Calcula o último dia do mês e ano selecionados
    const monthIndex = MONTHS.indexOf(month);
    const parsedYear = parseInt(year) || new Date().getFullYear();
    const lastDay = new Date(parsedYear, monthIndex + 1, 0).getDate();

    if (value > 0) {
      addTransactions([{ 
        day: lastDay.toString().padStart(2, '0'), 
        description: "Dízimo da Sede (10%)", 
        value, 
        type: TransactionType.EXIT 
      }]);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {}
      finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) { setIsListening(false); }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
                 {lastAddedId && <span className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full animate-ping"></span>}
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={() => isListening ? sessionRef.current?.stop() : startVoiceSession()} />

                <div className="flex flex-col gap-2">
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95">
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente no navegador</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage, parseTransactionInput } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Carregar dados salvos automaticamente ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Salvar automaticamente em cada mudança (Auto-Save Permanente)
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais e o saldo serão apagados permanentemente.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      setMonth(MONTHS[new Date().getMonth()]);
      setYear(new Date().getFullYear().toString());
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[], contextMonth?: string, contextYear?: string) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    // Determina o último dia do mês para correções automáticas (Dízimo da Sede)
    const targetMonth = contextMonth || month;
    const targetYear = contextYear || year;
    const monthIndex = MONTHS.indexOf(targetMonth);
    const parsedYear = parseInt(targetYear) || new Date().getFullYear();
    const lastDayStr = new Date(parsedYear, monthIndex + 1, 0).getDate().toString().padStart(2, '0');

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        let itemDay = data.day || new Date().getDate().toString().padStart(2, '0');

        // Regra de Negócio: Dízimo da Sede sempre no último dia
        if (normalizedDesc.toLowerCase().includes("dízimo da sede")) {
          itemDay = lastDayStr;
        }

        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
          lastId = updated[existingIndex].id;
        } else {
          const id = uuidv4();
          updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
          lastId = id;
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             const repasseId = uuidv4();
             updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    // Se editou a descrição para conter Dízimo da Sede, move para o último dia
    let finalItem = { ...updated };
    if (finalItem.description.toLowerCase().includes("dízimo da sede")) {
        const monthIndex = MONTHS.indexOf(month);
        const parsedYear = parseInt(year) || new Date().getFullYear();
        finalItem.day = new Date(parsedYear, monthIndex + 1, 0).getDate().toString().padStart(2, '0');
    }

    setTransactions(prev => prev.map(t => t.id === finalItem.id ? finalItem : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));

    if (value > 0) {
      addTransactions([{ 
        description: "Dízimo da Sede (10%)", 
        value, 
        type: TransactionType.EXIT 
      }]);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          let targetMonth = month;
          let targetYear = year;

          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) {
                  setMonth(matchedMonth);
                  targetMonth = matchedMonth;
              }
            }
            if (result.header.year) {
                setYear(result.header.year.toString());
                targetYear = result.header.year.toString();
            }
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            // Passamos o contexto de mês/ano extraído para garantir que a correção do último dia funcione imediatamente
            addTransactions(result.transactions, targetMonth, targetYear);
          }
        }
      } catch (err) {}
      finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) { setIsListening(false); }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
                 {lastAddedId && <span className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full animate-ping"></span>}
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={() => isListening ? sessionRef.current?.stop() : startVoiceSession()} />

                <div className="flex flex-col gap-2">
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95">
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente no navegador</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage, parseTransactionInput } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Carregar dados salvos automaticamente ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Salvar automaticamente em cada mudança (Auto-Save Permanente)
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais e o saldo serão apagados permanentemente.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      setMonth(MONTHS[new Date().getMonth()]);
      setYear(new Date().getFullYear().toString());
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');

        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
          lastId = updated[existingIndex].id;
        } else {
          const id = uuidv4();
          updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
          lastId = id;
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             const repasseId = uuidv4();
             updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));

    // Calcula o último dia do mês para o lançamento manual do dízimo
    const monthIndex = MONTHS.indexOf(month);
    const parsedYear = parseInt(year) || new Date().getFullYear();
    const lastDay = new Date(parsedYear, monthIndex + 1, 0).getDate();

    if (value > 0) {
      addTransactions([{ 
        day: lastDay.toString().padStart(2, '0'),
        description: "Dízimo da Sede (10%)", 
        value, 
        type: TransactionType.EXIT 
      }]);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {}
      finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) { setIsListening(false); }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
                 {lastAddedId && <span className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full animate-ping"></span>}
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={() => isListening ? sessionRef.current?.stop() : startVoiceSession()} />

                <div className="flex flex-col gap-2">
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95">
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente no navegador</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage, parseTransactionInput } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Carregar dados salvos automaticamente ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Salvar automaticamente em cada mudança (Auto-Save Permanente)
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais e o saldo serão apagados permanentemente.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      setMonth(MONTHS[new Date().getMonth()]);
      setYear(new Date().getFullYear().toString());
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');

        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
          lastId = updated[existingIndex].id;
        } else {
          const id = uuidv4();
          updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
          lastId = id;
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             const repasseId = uuidv4();
             updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));

    // Calcula o último dia do mês para o lançamento manual do dízimo
    const monthIndex = MONTHS.indexOf(month);
    const parsedYear = parseInt(year) || new Date().getFullYear();
    const lastDay = new Date(parsedYear, monthIndex + 1, 0).getDate();

    if (value > 0) {
      addTransactions([{ 
        day: lastDay.toString().padStart(2, '0'),
        description: "Dízimo da Sede (10%)", 
        value, 
        type: TransactionType.EXIT 
      }]);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {}
      finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), 
          onerror: () => setIsListening(false)
        }
      });

      // Salva a função de parada no ref
      sessionRef.current = { 
        stop: () => { 
          try {
            audioContext.close(); 
            stream.getTracks().forEach(t => t.stop()); 
            setIsListening(false);
          } catch (err) {
            console.error("Erro ao fechar sessão de voz:", err);
            setIsListening(false);
          }
        } 
      };

    } catch (e) { 
      setIsListening(false); 
      console.error("Erro ao iniciar microfone:", e);
    }
  };

  const handleToggleVoice = () => {
    if (isListening) {
      if (sessionRef.current && sessionRef.current.stop) {
        sessionRef.current.stop();
        sessionRef.current = null;
      } else {
        setIsListening(false);
      }
    } else {
      startVoiceSession();
    }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
                 {lastAddedId && <span className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full animate-ping"></span>}
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar 
                  onAdd={(item) => addTransactions([item])} 
                  isListening={isListening} 
                  onToggleVoice={handleToggleVoice} 
                />

                <div className="flex flex-col gap-2">
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95">
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente no navegador</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw, Save, Upload } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage, parseTransactionInput } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const fileInputRestoreRef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Carregar dados salvos automaticamente ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Salvar automaticamente em cada mudança (Auto-Save Permanente em Cache)
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  // Função para exportar os dados para um arquivo na pasta do usuário
  const handleExportBackup = () => {
    const dataToExport = {
      transactions,
      month,
      year,
      previousBalance,
      exportDate: new Date().toISOString()
    };
    const blob = new Blob([JSON.stringify(dataToExport, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `backup_idm_${month}_${year}.idm`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // Função para restaurar os dados de um arquivo
  const handleImportBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const data = JSON.parse(content);

        if (confirm("Deseja restaurar este backup? Os dados atuais serão substituídos.")) {
          setTransactions(data.transactions || []);
          setMonth(data.month || month);
          setYear(data.year || year);
          setPreviousBalance(data.previousBalance || '0.00');
          alert("Relatório restaurado com sucesso!");
        }
      } catch (err) {
        alert("Erro ao ler o arquivo de backup. Certifique-se de que é um arquivo .idm válido.");
      }
    };
    reader.readAsText(file);
    if (fileInputRestoreRef.current) fileInputRestoreRef.current.value = '';
  };

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais e o saldo serão apagados permanentemente.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      setMonth(MONTHS[new Date().getMonth()]);
      setYear(new Date().getFullYear().toString());
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');

        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
          lastId = updated[existingIndex].id;
        } else {
          const id = uuidv4();
          updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
          lastId = id;
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             const repasseId = uuidv4();
             updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));

    // Calcula o último dia do mês para o lançamento manual do dízimo
    const monthIndex = MONTHS.indexOf(month);
    const parsedYear = parseInt(year) || new Date().getFullYear();
    const lastDay = new Date(parsedYear, monthIndex + 1, 0).getDate();

    if (value > 0) {
      addTransactions([{ 
        day: lastDay.toString().padStart(2, '0'),
        description: "Dízimo da Sede (10%)", 
        value, 
        type: TransactionType.EXIT 
      }]);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {}
      finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), 
          onerror: () => setIsListening(false)
        }
      });

      // Salva a função de parada no ref
      sessionRef.current = { 
        stop: () => { 
          try {
            audioContext.close(); 
            stream.getTracks().forEach(t => t.stop()); 
            setIsListening(false);
          } catch (err) {
            console.error("Erro ao fechar sessão de voz:", err);
            setIsListening(false);
          }
        } 
      };

    } catch (e) { 
      setIsListening(false); 
      console.error("Erro ao iniciar microfone:", e);
    }
  };

  const handleToggleVoice = () => {
    if (isListening) {
      if (sessionRef.current && sessionRef.current.stop) {
        sessionRef.current.stop();
        sessionRef.current = null;
      } else {
        setIsListening(false);
      }
    } else {
      startVoiceSession();
    }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
                 {lastAddedId && <span className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full animate-ping"></span>}
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>

                {/* Botões de Manutenção do Relatório */}
                <div className="col-span-2 flex flex-col gap-2 pt-1">
                  <div className="grid grid-cols-2 gap-2">
                    <button onClick={handleExportBackup} className="flex items-center justify-center gap-2 py-2 bg-blue-600/10 hover:bg-blue-600/20 text-blue-400 border border-blue-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors" title="Salvar Backup na Pasta">
                      <Save size={14} /> Fazer Backup
                    </button>
                    <button onClick={() => fileInputRestoreRef.current?.click()} className="flex items-center justify-center gap-2 py-2 bg-green-600/10 hover:bg-green-600/20 text-green-500 border border-green-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors" title="Carregar Backup da Pasta">
                      <Upload size={14} /> Restaurar
                    </button>
                    <input type="file" ref={fileInputRestoreRef} accept=".idm,application/json" onChange={handleImportBackup} className="hidden" />
                  </div>
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar 
                  onAdd={(item) => addTransactions([item])} 
                  isListening={isListening} 
                  onToggleVoice={handleToggleVoice} 
                />

                <div className="flex flex-col gap-2">
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95">
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente no navegador</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage, parseTransactionInput } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Carregar dados salvos automaticamente ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Salvar automaticamente em cada mudança (Auto-Save Permanente em Cache)
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais e o saldo serão apagados permanentemente.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      setMonth(MONTHS[new Date().getMonth()]);
      setYear(new Date().getFullYear().toString());
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');

        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());
        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => 
          t.day === itemDay && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === finalType
        );

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
          lastId = updated[existingIndex].id;
        } else {
          const id = uuidv4();
          updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
          lastId = id;
        }

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const existingRepasse = updated.find(t => t.day === itemDay && t.description === repasseDesc && t.type === TransactionType.EXIT);
           if (!existingRepasse) {
             const repasseId = uuidv4();
             updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
           } else {
             existingRepasse.value += data.value;
           }
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));

    // Calcula o último dia do mês para o lançamento manual do dízimo
    const monthIndex = MONTHS.indexOf(month);
    const parsedYear = parseInt(year) || new Date().getFullYear();
    const lastDay = new Date(parsedYear, monthIndex + 1, 0).getDate();

    if (value > 0) {
      addTransactions([{ 
        day: lastDay.toString().padStart(2, '0'),
        description: "Dízimo da Sede (10%)", 
        value, 
        type: TransactionType.EXIT 
      }]);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {}
      finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), 
          onerror: () => setIsListening(false)
        }
      });

      // Salva a função de parada no ref
      sessionRef.current = { 
        stop: () => { 
          try {
            audioContext.close(); 
            stream.getTracks().forEach(t => t.stop()); 
            setIsListening(false);
          } catch (err) {
            console.error("Erro ao fechar sessão de voz:", err);
            setIsListening(false);
          }
        } 
      };

    } catch (e) { 
      setIsListening(false); 
      console.error("Erro ao iniciar microfone:", e);
    }
  };

  const handleToggleVoice = () => {
    if (isListening) {
      if (sessionRef.current && sessionRef.current.stop) {
        sessionRef.current.stop();
        sessionRef.current = null;
      } else {
        setIsListening(false);
      }
    } else {
      startVoiceSession();
    }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
                 {lastAddedId && <span className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full animate-ping"></span>}
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>

                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar 
                  onAdd={(item) => addTransactions([item])} 
                  isListening={isListening} 
                  onToggleVoice={handleToggleVoice} 
                />

                <div className="flex flex-col gap-2">
                   <button onClick={() => fileInputIARef.current?.click()} disabled={isProcessingIA} className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95">
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente no navegador</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw, ShieldCheck, Key } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage } from './services/geminiService';

declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  // Estados de Controle de Inicialização e Bug do Celular
  const [isAppInitialized, setIsAppInitialized] = useState(false);
  const [needsKey, setNeedsKey] = useState(true);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // 1. Efeito de Inicialização Segura
  useEffect(() => {
    const checkStatus = async () => {
      // Verifica se o usuário já estava no meio de uma operação de arquivo (evita reset no mobile)
      const pickingFile = sessionStorage.getItem('picking_file') === 'true';
      const alreadyInitialized = localStorage.getItem('idm_app_initialized') === 'true';

      let hasKey = false;
      try {
        hasKey = await window.aistudio.hasSelectedApiKey();
      } catch (e) {
        console.error("Erro ao checar API Key", e);
      }

      if (hasKey || pickingFile) {
        setNeedsKey(false);
        setIsAppInitialized(true);
        sessionStorage.removeItem('picking_file'); // Limpa após retornar
      }

      // Carregar dados salvos
      const saved = localStorage.getItem('idm_report_data');
      if (saved) {
        try {
          const data = JSON.parse(saved);
          setTransactions(data.transactions || []);
          setMonth(data.month || MONTHS[new Date().getMonth()]);
          setYear(data.year || new Date().getFullYear().toString());
          setPreviousBalance(data.previousBalance?.toString() || '0.00');
        } catch (e) {
          console.error("Erro ao carregar dados locais", e);
        }
      }
    };

    checkStatus();

    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // 2. Salvar automaticamente em cada mudança
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  // Função para Iniciar o App e Pedir Permissões/Chave
  const handleStartApp = async () => {
    try {
      await window.aistudio.openSelectKey();
      // Assume sucesso imediato para evitar race condition
      setNeedsKey(false);
      setIsAppInitialized(true);
      localStorage.setItem('idm_app_initialized', 'true');
    } catch (e) {
      console.error("Erro ao abrir seleção de chave", e);
    }
  };

  const stopVoiceIfActive = () => {
    if (isListening && sessionRef.current) {
      sessionRef.current.stop();
    }
  };

  const openFilePicker = () => {
    stopVoiceIfActive();
    // Marca que estamos saindo para buscar um arquivo para o navegador não resetar o app
    sessionStorage.setItem('picking_file', 'true');
    fileInputIARef.current?.click();
  };

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview, isAppInitialized]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais serão apagados.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');
        const finalType = data.type;

        const id = uuidv4();
        updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
        lastId = id;

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const repasseId = uuidv4();
           updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    const monthIndex = MONTHS.indexOf(month);
    const parsedYear = parseInt(year) || new Date().getFullYear();
    const lastDay = new Date(parsedYear, monthIndex + 1, 0).getDate();

    if (value > 0) {
      addTransactions([{ 
        day: lastDay.toString().padStart(2, '0'),
        description: "Dízimo da Sede (10%)", 
        value, 
        type: TransactionType.EXIT 
      }]);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) {
      sessionStorage.removeItem('picking_file');
      return;
    }

    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {
        if (err instanceof Error && err.message.includes("Requested entity was not found")) {
           setNeedsKey(true);
        }
      } finally {
        setIsProcessingIA(false);
        sessionStorage.removeItem('picking_file');
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), 
          onerror: () => setIsListening(false)
        }
      });

      sessionRef.current = { 
        stop: () => { 
          try {
            audioContext.close(); 
            stream.getTracks().forEach(t => t.stop()); 
            setIsListening(false);
          } catch (err) {
            setIsListening(false);
          }
        } 
      };
    } catch (e) { 
      setIsListening(false); 
    }
  };

  const handleToggleVoice = () => {
    if (isListening) {
      sessionRef.current?.stop();
    } else {
      startVoiceSession();
    }
  };

  // TELA DE BOAS-VINDAS / PERMISSÕES (ESTILO IDM)
  if (needsKey && !sessionStorage.getItem('picking_file')) {
    return (
      <div className="fixed inset-0 z-[500] bg-slate-950 flex flex-col items-center justify-center p-6 text-center">
        <div className="w-24 h-24 mb-6 animate-bounce">
          <svg viewBox="0 0 100 120" className="w-full h-full">
            <path d="M50 10 C30 40 20 60 20 80 C20 100 35 110 50 110 C65 110 80 100 80 80 C80 60 70 40 50 10 Z" fill="none" stroke="#d93025" strokeWidth="3" />
            <path d="M50 25 C40 50 35 65 35 80 C35 90 40 95 50 95 C60 95 65 90 65 80 C65 65 60 50 50 25 Z" fill="#d93025" />
          </svg>
        </div>
        <h1 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Tesouraria IDM</h1>
        <p className="text-slate-400 text-sm max-w-xs mb-8">Para começar, precisamos ativar as permissões de inteligência e segurança.</p>

        <div className="space-y-3 w-full max-w-xs">
          <button 
            onClick={handleStartApp}
            className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-2xl transition-all active:scale-95"
          >
            <ShieldCheck size={20} /> Iniciar e Dar Permissão
          </button>
          <a 
            href="https://ai.google.dev/gemini-api/docs/billing" 
            target="_blank" 
            rel="noopener noreferrer"
            className="block text-[10px] text-slate-500 uppercase font-bold hover:text-blue-400 underline"
          >
            Sobre faturamento e chaves API
          </a>
        </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar 
                  onAdd={(item) => addTransactions([item])} 
                  isListening={isListening} 
                  onToggleVoice={handleToggleVoice} 
                />

                <div className="flex flex-col gap-2">
                   <button 
                     onClick={openFilePicker} 
                     disabled={isProcessingIA} 
                     className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95"
                   >
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw, ShieldCheck, Key } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage } from './services/geminiService';

// The aistudio interface is globally provided by the environment, so we don't need to re-declare it here.

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  // Estados de Controle de Inicialização e Bug do Celular
  const [isAppInitialized, setIsAppInitialized] = useState(false);
  const [needsKey, setNeedsKey] = useState(true);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // 1. Efeito de Inicialização Segura
  useEffect(() => {
    const checkStatus = async () => {
      // Verifica se o usuário já estava no meio de uma operação de arquivo (evita reset no mobile)
      const pickingFile = sessionStorage.getItem('picking_file') === 'true';
      const alreadyInitialized = localStorage.getItem('idm_app_initialized') === 'true';

      let hasKey = false;
      try {
        // @ts-ignore - Assuming aistudio is globally available
        hasKey = await window.aistudio.hasSelectedApiKey();
      } catch (e) {
        console.error("Erro ao checar API Key", e);
      }

      if (hasKey || pickingFile) {
        setNeedsKey(false);
        setIsAppInitialized(true);
        sessionStorage.removeItem('picking_file'); // Limpa após retornar
      }

      // Carregar dados salvos
      const saved = localStorage.getItem('idm_report_data');
      if (saved) {
        try {
          const data = JSON.parse(saved);
          setTransactions(data.transactions || []);
          setMonth(data.month || MONTHS[new Date().getMonth()]);
          setYear(data.year || new Date().getFullYear().toString());
          setPreviousBalance(data.previousBalance?.toString() || '0.00');
        } catch (e) {
          console.error("Erro ao carregar dados locais", e);
        }
      }
    };

    checkStatus();

    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // 2. Salvar automaticamente em cada mudança
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  // Função para Iniciar o App e Pedir Permissões/Chave
  const handleStartApp = async () => {
    try {
      // @ts-ignore - Assuming aistudio is globally available
      await window.aistudio.openSelectKey();
      // Assume sucesso imediato para evitar race condition
      setNeedsKey(false);
      setIsAppInitialized(true);
      localStorage.setItem('idm_app_initialized', 'true');
    } catch (e) {
      console.error("Erro ao abrir seleção de chave", e);
    }
  };

  const stopVoiceIfActive = () => {
    if (isListening && sessionRef.current) {
      sessionRef.current.stop();
    }
  };

  const openFilePicker = () => {
    stopVoiceIfActive();
    // Marca que estamos saindo para buscar um arquivo para o navegador não resetar o app
    sessionStorage.setItem('picking_file', 'true');
    fileInputIARef.current?.click();
  };

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview, isAppInitialized]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais serão apagados.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');
        const finalType = data.type;

        const id = uuidv4();
        updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
        lastId = id;

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const repasseId = uuidv4();
           updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    const monthIndex = MONTHS.indexOf(month);
    const parsedYear = parseInt(year) || new Date().getFullYear();
    const lastDay = new Date(parsedYear, monthIndex + 1, 0).getDate();

    if (value > 0) {
      addTransactions([{ 
        day: lastDay.toString().padStart(2, '0'),
        description: "Dízimo da Sede (10%)", 
        value, 
        type: TransactionType.EXIT 
      }]);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) {
      sessionStorage.removeItem('picking_file');
      return;
    }

    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {
        if (err instanceof Error && err.message.includes("Requested entity was not found")) {
           setNeedsKey(true);
        }
      } finally {
        setIsProcessingIA(false);
        sessionStorage.removeItem('picking_file');
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    // Create a new GoogleGenAI instance right before making an API call to ensure it uses the latest API key.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }

              // Manual encoding logic for PCM data to base64
              const bytes = new Uint8Array(int16.buffer);
              let binary = '';
              const len = bytes.byteLength;
              for (let i = 0; i < len; i++) {
                binary += String.fromCharCode(bytes[i]);
              }
              const base64 = btoa(binary);

              // Use sessionPromise.then to ensure data is streamed only after the session promise resolves.
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), 
          onerror: () => setIsListening(false)
        }
      });

      sessionRef.current = { 
        stop: () => { 
          try {
            audioContext.close(); 
            stream.getTracks().forEach(t => t.stop()); 
            setIsListening(false);
          } catch (err) {
            setIsListening(false);
          }
        } 
      };
    } catch (e) { 
      setIsListening(false); 
    }
  };

  const handleToggleVoice = () => {
    if (isListening) {
      sessionRef.current?.stop();
    } else {
      startVoiceSession();
    }
  };

  // TELA DE BOAS-VINDAS / PERMISSÕES (ESTILO IDM)
  if (needsKey && !sessionStorage.getItem('picking_file')) {
    return (
      <div className="fixed inset-0 z-[500] bg-slate-950 flex flex-col items-center justify-center p-6 text-center">
        <div className="w-24 h-24 mb-6 animate-bounce">
          <svg viewBox="0 0 100 120" className="w-full h-full">
            <path d="M50 10 C30 40 20 60 20 80 C20 100 35 110 50 110 C65 110 80 100 80 80 C80 60 70 40 50 10 Z" fill="none" stroke="#d93025" strokeWidth="3" />
            <path d="M50 25 C40 50 35 65 35 80 C35 90 40 95 50 95 C60 95 65 90 65 80 C65 65 60 50 50 25 Z" fill="#d93025" />
          </svg>
        </div>
        <h1 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Tesouraria IDM</h1>
        <p className="text-slate-400 text-sm max-w-xs mb-8">Para começar, precisamos ativar as permissões de inteligência e segurança.</p>

        <div className="space-y-3 w-full max-w-xs">
          <button 
            onClick={handleStartApp}
            className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-2xl transition-all active:scale-95"
          >
            <ShieldCheck size={20} /> Iniciar e Dar Permissão
          </button>
          <a 
            href="https://ai.google.dev/gemini-api/docs/billing" 
            target="_blank" 
            rel="noopener noreferrer"
            className="block text-[10px] text-slate-500 uppercase font-bold hover:text-blue-400 underline"
          >
            Sobre faturamento e chaves API
          </a>
        </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar 
                  onAdd={(item) => addTransactions([item])} 
                  isListening={isListening} 
                  onToggleVoice={handleToggleVoice} 
                />

                <div className="flex flex-col gap-2">
                   <button 
                     onClick={openFilePicker} 
                     disabled={isProcessingIA} 
                     className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95"
                   >
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { TransactionType } from "../types";

const SYSTEM_INSTRUCTION = `
Você é um tesoureiro experiente da 'Igreja de Deus Missionária'.

Sua tarefa é analisar relatórios financeiros (textos ou imagens) e extrair dados estruturados.

REGRAS DE EXTRAÇÃO DE CABEÇALHO:
1. Localize o MÊS e o ANO do relatório.
2. Localize o SALDO ANTERIOR. Geralmente está escrito "SALDO ANTERIOR" e possui um valor numérico ao lado.

REGRAS DE LANÇAMENTOS:
1. Identifique se é ENTRADA ou SAIDA.
    - SAIDA: Compra, Pagamento, Gasto, Retirada, Ajuda, "passar", "pagar", "gas", "luz", "água", "gratificação", "Oferta pregador", "Oferta missionária", "Ajuda social", "Gratificação do obreiro", "Oferta Obreiro".
    - ENTRADA: Dízimo, Oferta (exceto ao pregador), Voto, Doação, "receber", "Santa Ceia", "Culto de Ceia".
2. Extraia DIA, VALOR e DESCRIÇÃO (formalize o texto).
3. Se o texto conter "semid", "cemid" ou similar, a DESCRIÇÃO deve ser: "REPASSE SEMID".
4. "luz" -> "Energia Elétrica", "gas" -> "Gás de Cozinha".

Retorne um objeto JSON seguindo estritamente o schema fornecido.
`;

const RESPONSE_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    header: {
      type: Type.OBJECT,
      properties: {
        month: { type: Type.STRING, description: "Nome do mês encontrado no relatório" },
        year: { type: Type.STRING, description: "Ano do relatório" },
        previousBalance: { type: Type.NUMBER, description: "Valor do Saldo Anterior encontrado" }
      }
    },
    transactions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.STRING },
          description: { type: Type.STRING },
          value: { type: Type.NUMBER },
          type: { type: Type.STRING, enum: [TransactionType.ENTRY, TransactionType.EXIT] }
        },
        required: ["description", "value", "type"],
      }
    }
  },
  required: ["transactions"]
};

export const parseTransactionInput = async (
  inputText: string
): Promise<any | null> => {
  if (!inputText.trim()) return null;

  // Create a new GoogleGenAI instance right before making an API call to ensure it always uses the most up-to-date API key.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const prompt = `Analise o texto e extraia os dados: "${inputText}"`;
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error("Gemini Parse Error:", error);
    return null;
  }
};

export const parseTransactionImage = async (
  base64Data: string,
  mimeType: string
): Promise<any | null> => {
  // Create a new GoogleGenAI instance right before making an API call to ensure it always uses the most up-to-date API key.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const prompt = `
      Analise esta imagem/PDF de um relatório financeiro.
      Extraia o Mês, Ano, Saldo Anterior e todos os lançamentos da tabela.
      Se não encontrar mês, ano ou saldo, deixe os campos do cabeçalho nulos ou vazios no JSON, mas extraia as transações.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType, data: base64Data } },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error("Gemini Image Parse Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, Maximize2, Minimize2, Edit3, X, Eye, Sparkles, Loader2, Landmark, Camera, RotateCcw } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { parseTransactionImage } from './services/geminiService';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.25);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isProcessingIA, setIsProcessingIA] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [lastAddedId, setLastAddedId] = useState<string | null>(null);

  const fileInputIARef = useRef<HTMLInputElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);
  const [isListening, setIsListening] = useState(false);

  const A4_WIDTH_PX = 794;

  // Carregar dados salvos automaticamente ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setTransactions(data.transactions || []);
        setMonth(data.month || MONTHS[new Date().getMonth()]);
        setYear(data.year || new Date().getFullYear().toString());
        setPreviousBalance(data.previousBalance?.toString() || '0.00');
      } catch (e) {
        console.error("Erro ao carregar dados locais", e);
      }
    }
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Salvar automaticamente em cada mudança
  useEffect(() => {
    const dataToSave = { transactions, month, year, previousBalance };
    localStorage.setItem('idm_report_data', JSON.stringify(dataToSave));
  }, [transactions, month, year, previousBalance]);

  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;
    transactions.forEach(t => {
      const desc = t.description.toLowerCase();
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) dizimoSede += t.value;
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) repasseSemid += t.value;
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) parcelasSede += t.value;
    });
    return { dizimoSede, repasseSemid, parcelasSede, total: dizimoSede + repasseSemid + parcelasSede };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.1));
    }
  };

  useEffect(() => {
    const timer = setTimeout(handleFitWidth, 300);
    window.addEventListener('resize', handleFitWidth);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', handleFitWidth);
    };
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  const handleNewReport = () => {
    if (confirm("Deseja iniciar um novo relatório? ATENÇÃO: Todos os lançamentos atuais serão apagados.")) {
      setTransactions([]);
      setPreviousBalance('0.00');
      localStorage.removeItem('idm_report_data');
    }
  };

  const addTransactions = (newItems: any[]) => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(30);
    }

    setTransactions(prev => {
      let updated = [...prev];
      let lastId = null;

      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const itemDay = data.day || new Date().getDate().toString().padStart(2, '0');
        const finalType = data.type;

        const id = uuidv4();
        updated.push({ id, day: itemDay, description: normalizedDesc, value: data.value, type: finalType });
        lastId = id;

        if (data.type === TransactionType.ENTRY && normalizedDesc.toLowerCase().includes("ceia")) {
           const repasseDesc = "REPASSE SEMID";
           const repasseId = uuidv4();
           updated.push({ id: repasseId, day: itemDay, description: repasseDesc, value: data.value, type: TransactionType.EXIT });
        }
      });

      if (lastId) {
        setLastAddedId(lastId);
        setTimeout(() => setLastAddedId(null), 3000);
      }

      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    const monthIndex = MONTHS.indexOf(month);
    const parsedYear = parseInt(year) || new Date().getFullYear();
    const lastDay = new Date(parsedYear, monthIndex + 1, 0).getDate();

    if (value > 0) {
      addTransactions([{ 
        day: lastDay.toString().padStart(2, '0'),
        description: "Dízimo da Sede (10%)", 
        value, 
        type: TransactionType.EXIT 
      }]);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_Final_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true, letterRendering: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  const handleImportIA = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessingIA(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Content = (reader.result as string).split(',')[1];
        const result = await parseTransactionImage(base64Content, file.type);
        if (result) {
          if (result.header) {
            if (result.header.month) {
              const matchedMonth = MONTHS.find(m => m.toLowerCase() === result.header.month.toLowerCase());
              if (matchedMonth) setMonth(matchedMonth);
            }
            if (result.header.year) setYear(result.header.year.toString());
            if (result.header.previousBalance !== undefined) setPreviousBalance(result.header.previousBalance.toString());
          }
          if (result.transactions && result.transactions.length > 0) {
            addTransactions(result.transactions);
          }
        }
      } catch (err) {
        console.error(err);
      } finally {
        setIsProcessingIA(false);
        if (fileInputIARef.current) fileInputIARef.current.value = '';
      }
    };
  };

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [{
            name: 'add_entry',
            description: 'Adiciona transação.',
            parameters: { type: Type.OBJECT, properties: { day: { type: Type.STRING }, description: { type: Type.STRING }, value: { type: Type.NUMBER }, type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] } }, required: ['description', 'value', 'type'] }
          }]}],
          systemInstruction: 'Tesouraria IDM. Extraia dia, valor e tipo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;

              const bytes = new Uint8Array(int16.buffer);
              let binary = '';
              const len = bytes.byteLength;
              for (let i = 0; i < len; i++) binary += String.fromCharCode(bytes[i]);
              const base64 = btoa(binary);

              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor); processor.connect(audioContext.destination); setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false), 
          onerror: () => setIsListening(false)
        }
      });

      sessionRef.current = { 
        stop: () => { 
          try {
            audioContext.close(); 
            stream.getTracks().forEach(t => t.stop()); 
            setIsListening(false);
          } catch (err) {
            setIsListening(false);
          }
        } 
      };
    } catch (e) { 
      setIsListening(false); 
    }
  };

  const handleToggleVoice = () => {
    if (isListening) {
      sessionRef.current?.stop();
    } else {
      startVoiceSession();
    }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {!isFullPreview && (
        <div className="w-full lg:w-[75%] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-base font-bold text-yellow-500 flex items-center gap-2 uppercase tracking-tight">
              <Calculator size={18} /> Financeiro IDM
            </h1>
            <div className="flex gap-1">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia">
                 {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg lg:hidden" title="Ver Folha">
                 <Eye size={16} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar pb-10">

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="grid grid-cols-2 gap-3 bg-slate-800/20 p-4 rounded-xl border border-slate-800 md:col-span-2 lg:col-span-1">
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Mês</label>
                  <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="col-span-1">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Ano</label>
                  <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] uppercase text-slate-500 font-bold block mb-1">Saldo Anterior (R$)</label>
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm font-mono outline-none" />
                </div>
                <div className="col-span-2 pt-1">
                  <button onClick={handleNewReport} className="w-full flex items-center justify-center gap-2 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/20 rounded-lg text-[10px] font-bold uppercase transition-colors">
                    <RotateCcw size={14} /> Iniciar Novo Relatório
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <InputBar 
                  onAdd={(item) => addTransactions([item])} 
                  isListening={isListening} 
                  onToggleVoice={handleToggleVoice} 
                />

                <div className="flex flex-col gap-2">
                   <button 
                     onClick={() => fileInputIARef.current?.click()} 
                     disabled={isProcessingIA} 
                     className="w-full flex items-center justify-center gap-3 px-4 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-900/20 transition-all active:scale-95"
                   >
                     {isProcessingIA ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />} 
                     Importar de Foto ou PDF (Relatório Antigo)
                   </button>
                   <input type="file" ref={fileInputIARef} accept="image/*,application/pdf" onChange={handleImportIA} className="hidden" />
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest px-1 flex items-center justify-between">
                Lançamentos Registrados
                <button onClick={calculateDizimoSede} className="text-purple-400 hover:text-purple-300 flex items-center gap-1 font-bold text-[9px] uppercase">
                  <Sparkles size={12}/> Calcular Dízimo Sede
                </button>
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className={`group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all ${lastAddedId === t.id ? 'ring-2 ring-blue-500 bg-blue-500/10' : ''}`}>
                    <div className="flex flex-col min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-bold px-1.5 py-0.5 bg-slate-950 text-slate-400 rounded uppercase">Dia {t.day}</span>
                        <span className={`text-[8px] font-black uppercase ${t.type === TransactionType.ENTRY ? 'text-green-500' : 'text-red-500'}`}>{t.type}</span>
                      </div>
                      <span className="text-xs font-semibold text-slate-200 uppercase truncate mt-1">{t.description}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className={`font-mono text-sm font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>{t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      <div className="flex gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/30 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-800 max-w-sm">
               <div className="flex items-center gap-2 mb-3 text-slate-400">
                  <Landmark size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Resumo p/ Sede (Informativo)</span>
               </div>
               <div className="bg-slate-800/40 rounded-xl p-4 space-y-2 border border-slate-800/50">
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Dízimo Sede + SEMID:</span><span className="font-mono font-bold text-slate-300">R$ {(sedeSummary.dizimoSede + sedeSummary.repasseSemid).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="flex justify-between text-[11px] text-slate-500"><span>Parcelas/Compras:</span><span className="font-mono font-bold text-slate-300">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
                  <div className="pt-2 border-t border-slate-700 flex justify-between items-center"><span className="text-[11px] font-black text-yellow-500/80 uppercase">Total a Entregar:</span><span className="text-base font-mono font-black text-yellow-500">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span></div>
               </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 uppercase text-sm shadow-xl shadow-yellow-500/10 transition-all active:scale-95">
              {isGeneratingPdf ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />} BAIXAR RELATÓRIO FINAL (PDF)
            </button>
            <p className="text-[9px] text-slate-600 text-center mt-2 font-bold uppercase tracking-tighter">O sistema salva seu progresso automaticamente</p>
          </div>
        </div>
      )}

      <div className={`flex flex-col bg-slate-900 border-l border-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full fixed inset-0 z-[100]' : 'w-full lg:w-[25%] h-[35%] lg:h-full'}`}>
        <div className="absolute top-4 right-4 z-40 flex gap-2">
           {isFullPreview && <button onClick={() => setIsFullPreview(false)} className="bg-red-600 p-3 rounded-full text-white shadow-2xl hover:scale-110 transition-transform"><X size={20} /></button>}
        </div>
        <div className="h-10 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-3 shrink-0">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Visualização Folha A4</span>
           <div className="flex items-center gap-2 bg-slate-900 rounded-lg px-2 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.05, z-0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomOut size={14}/></button>
             <span className="text-[9px] font-mono font-bold text-slate-400 w-8 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.05))} className="p-1 text-slate-500 hover:text-white"><ZoomIn size={14}/></button>
             <button onClick={handleFitWidth} className="p-1 text-slate-500 hover:text-blue-400 ml-1 border-l border-slate-800 pl-1"><Maximize2 size={12}/></button>
           </div>
        </div>
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 flex justify-center bg-slate-800/30 items-start custom-scrollbar">
           <div className="origin-top transition-transform duration-200 shadow-2xl mb-12" style={{ transform: `scale(${zoom})`, minWidth: `${A4_WIDTH_PX}px` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} highlightId={lastAddedId} />
              </div>
           </div>
        </div>
      </div>

      {editingTransaction && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-sm uppercase flex items-center gap-2"><Edit3 size={16}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-500 hover:text-white transition-colors"><X size={24}/></button>
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-4 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none" />
                </div>
                <div className="col-span-3">
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs uppercase outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs font-mono outline-none" />
                </div>
                <div>
                  <label className="text-[9px] uppercase font-bold text-slate-500 block mb-1">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs outline-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option><option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold uppercase text-[10px] transition-colors">Cancelar</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase text-[10px] transition-colors shadow-lg shadow-blue-900/20">Salvar Alterações</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
